import findRoot from 'find-root';
import path from 'path';
import Minilog from 'minilog';  // the one true minilog instance

import { logUncaught, logUnhandled } from './uncaught-unhandled';
import FileBackend from './file-backend';
import syslogBackend from './syslog-backend';  // GLOBAL.syslogBackend

let defaultLogDir = null;


//Minilog.enable();  // this is what you would normally do, it sets up the defaults
// instead we are going to tweak things a bit
// reference http://mixu.net/minilog/filter.html
if (Minilog.defaultFormatter) {
    Minilog
        .pipe(Minilog.suggest.deny(/.*/, 'info'))  // suppress messages < 'info' (no debug)
        .pipe(Minilog.defaultFormatter)
        .pipe(Minilog.defaultBackend);
} else {
    Minilog
        .pipe(Minilog.suggest.deny(/.*/, 'info'))  // suppress messages < 'info' (no debug)
        .pipe(Minilog.defaultBackend);
}


class JiboLog {
    constructor(name) {
        this.name = name || '[unknown module]';
        if (name && name.indexOf('/') === 0) {  // should this perhaps be path.isAbsolute? FIXME
            this.origname = name;
            this.name = path.basename(name);
        }
        this.minilog = Minilog(this.name);
        //handleUncaughtAndUnhandled();  // off by default now

        // always say we will try to pipe to syslogBackend; the filter is done in the write method
        Minilog.pipe(syslogBackend);
    }

    log()   {
        this.minilog.log.apply(Minilog, arguments); // alias for debug
    }
    debug() {
        this.minilog.debug.apply(Minilog, arguments);
    }
    info()  {
        this.minilog.info.apply(Minilog, arguments);
    }
    warn()  {
        this.minilog.warn.apply(Minilog, arguments);
    }
    error() {
        this.minilog.error.apply(Minilog, arguments);
    }

    // our own additions
    iferr(err, ...args) {
        if (err) {
            // // not using [].slice here for performance reasons
            // // see section 3.2 https://github.com/petkaantonov/bluebird/wiki/Optimization-killers
            // let args = new Array(arguments.length);
            // for (let i=0; i < args.length; ++i) {
            //     args[i] = arguments[i];  // i must always be valid for arguments object
            // }

            // converted the above to use the ES6 ... operator instead
            args.push(err);  // put the error object on the end
            this.minilog.error.apply(Minilog, args);
        }
    }


    enableDebug(name, level='debug') {
        name = name || this.name;
        Minilog.suggest.allow(name, level);
    }


    toFile(filename=null, callback=null) {
        if(process.platform === 'linux' && process.arch === 'arm') {
            if (callback) {
                console.warn("Disable 'toFile' on robot.");
                callback("Disabled 'toFile' on robot.");
            }

            return;
        }

        // note: we might be logging to multiple files (so can't use this.fileBackend)
        let fileBackend = new FileBackend(filename, defaultLogDir);
        fileBackend.init( () => {
            Minilog.pipe(fileBackend);
            if (callback) {
                callback();
            }
        });
    }


    setDefaultLogDir(directory, callback) {
        defaultLogDir = directory;
        if (callback) {  // for backwards compatibility
            setImmediate(callback);
        }
    }


    toSyslog() {
        // enable
        if (this.name) {
            syslogBackend.allow(this.name);
        }
    }


    toCloud() { //minBatchSize, maxBatchSize, idleUploadTimeout) {
        console.log("DEPRECATED- use toSyslog()");
    }
    toCloudConnect() { //accessKey, region, jiboId, callback) {
        console.log("DEPRECATED- use toSyslog()");
    }
    toCloudDisable() {
        console.log("DEPRECATED- use toSyslog()");
    }


    enableUncaughtAndUnhandled() {
        handleUncaughtAndUnhandled();
    }


    disableUncaughtAndUnhandled() {
        stopHandlingUncaughtAndUnhandled();
    }


    static version() {
        let rootPath = findRoot(module.filename);
        return require( path.resolve(rootPath, 'package.json') ).version;
    }

}


let handlersInstalledOnce = false;
let uncaughtCallback;
let unhandledCallback;
function handleUncaughtAndUnhandled() {
    if (!handlersInstalledOnce && (typeof process === 'object')) {  // only when running under node
        let minilog = Minilog('[uncaught]');
        // log uncaughtExceptions
        uncaughtCallback = (err) => { logUncaught(minilog, err); };
        unhandledCallback = (reason, p) => { logUnhandled(minilog, reason, p); };
        
        process.on('uncaughtException', uncaughtCallback);
        // log any unhandled, otherwise silent, promise exceptions too
        process.on('unhandledRejection', unhandledCallback);

        handlersInstalledOnce = true;
    }
}

function stopHandlingUncaughtAndUnhandled() {
    if (handlersInstalledOnce) {
        process.removeListener('uncaughtException', uncaughtCallback);
        process.removeListener('unhandledRejection', unhandledCallback);
        handlersInstalledOnce = false;
    }
}


// we want to insure there is only ever one instance of the JiboLog module
// because of the file scope variables and especially the Minilog instance
import JiboSingletons from './JiboSingletons';
export default JiboSingletons.enforceSingleton(JiboLog, 'JiboLog');



